{
    "level": "A2–B1",
    "intro": "W tym temacie nauczysz się rozpoznawać <strong>stative verbs</strong> — czasowniki, które opisują <strong>stan</strong>, a nie aktywne działanie.",
    "rules": [
        {
            "label": "STATE, NOT ACTION",
            "color": "emerald",
            "text": "Stative verbs mówią o opinii, uczuciu, posiadaniu, percepcji albo stanie.",
            "example": "know, believe, own, love, seem"
        },
        {
            "label": "USUALLY NOT CONTINUOUS",
            "color": "blue",
            "text": "Takich czasowników <strong>zwykle nie używamy w Continuous</strong>.",
            "example": "I know the answer. not I am knowing the answer."
        },
        {
            "label": "SOME VERBS CHANGE MEANING",
            "color": "amber",
            "text": "Niektóre czasowniki mogą być stative albo dynamic w zależności od znaczenia.",
            "example": "I think he is right. / I am thinking about the problem."
        }
    ]
}

{
    "title": "1. Główne grupy",
    "intro": "Najczęściej czasowniki stanu można podzielić na kilka typowych grup.",
    "items": [
        {
            "label": "Thinking / opinion",
            "title": "know, believe, understand, remember",
            "subtitle": "myśl, wiedza, rozumienie"
        },
        {
            "label": "Possession",
            "title": "have, own, belong, need",
            "subtitle": "posiadanie albo przynależność"
        },
        {
            "label": "Senses / perception",
            "title": "see, hear, smell, taste, seem",
            "subtitle": "percepcja albo wrażenie"
        },
        {
            "label": "Emotions / state",
            "title": "love, like, hate, want, prefer",
            "subtitle": "emocje, chęci, stany"
        }
    ]
}

{
    "title": "2. Kiedy używać stative verbs",
    "sections": [
        {
            "label": "Myśl i wiedza",
            "color": "emerald",
            "description": "Przy ideach, przekonaniach, pamięci i rozumieniu zwykle wybieramy <strong>simple form</strong>, a nie continuous form.",
            "examples": [
                {
                    "en": "I know her name.",
                    "ua": "Znam jej imię."
                },
                {
                    "en": "We believe you.",
                    "ua": "Wierzymy ci."
                },
                {
                    "en": "She understands the rule.",
                    "ua": "Ona rozumie tę zasadę."
                }
            ]
        },
        {
            "label": "Posiadanie i przynależność",
            "color": "blue",
            "description": "Gdy czasownik pokazuje, że ktoś <strong>ma</strong>, <strong>posiada</strong> albo coś <strong>należy</strong> do kogoś, continuous form jest zwykle błędna.",
            "examples": [
                {
                    "en": "They own a small cafe.",
                    "ua": "Mają małą kawiarnię."
                },
                {
                    "en": "This bag belongs to me.",
                    "ua": "Ta torba należy do mnie."
                },
                {
                    "en": "I need more time.",
                    "ua": "Potrzebuję więcej czasu."
                }
            ]
        },
        {
            "label": "Percepcja i emocje",
            "color": "amber",
            "description": "Czasowniki odczuć, wrażeń i emocji też często zachowują się jak stative verbs.",
            "examples": [
                {
                    "en": "I see the problem now.",
                    "ua": "Widzę teraz problem."
                },
                {
                    "en": "This soup tastes great.",
                    "ua": "Ta zupa świetnie smakuje."
                },
                {
                    "en": "She loves jazz.",
                    "ua": "Ona kocha jazz."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy Continuous jest możliwy",
    "sections": [
        {
            "label": "Zmiana znaczenia",
            "color": "violet",
            "description": "Niektóre czasowniki mogą mieć <strong>inne znaczenie</strong> w continuous form i wtedy stają się dynamic.",
            "examples": [
                {
                    "en": "I think he is right.",
                    "ua": "Myślę, że on ma rację."
                },
                {
                    "en": "I am thinking about our next trip.",
                    "ua": "Myślę o naszej następnej podróży."
                },
                {
                    "en": "She has a new laptop.",
                    "ua": "Ona ma nowy laptop."
                },
                {
                    "en": "She is having lunch.",
                    "ua": "Ona je lunch."
                }
            ]
        },
        {
            "label": "Uważaj na see / taste / smell",
            "color": "sky",
            "description": "Jeśli chodzi o ogólną percepcję, czasownik często jest stative. Jeśli o aktywne działanie, Continuous może być możliwy.",
            "examples": [
                {
                    "en": "I see what you mean.",
                    "ua": "Rozumiem, co masz na myśli."
                },
                {
                    "en": "The chef is tasting the sauce.",
                    "ua": "Szef kuchni próbuje sosu."
                },
                {
                    "en": "I smell smoke.",
                    "ua": "Czuję zapach dymu."
                }
            ],
            "note": "Zapytaj siebie, czy to stan / wrażenie, czy realna czynność w toku."
        }
    ]
}

{
    "title": "4. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Continuous z typowym czasownikiem stanu.",
            "wrong": "I am knowing the answer.",
            "right": "✅ <span class=\"font-mono\">I know the answer.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Continuous z czasownikiem uczucia w podstawowym znaczeniu.",
            "wrong": "She is loving jazz.",
            "right": "✅ <span class=\"font-mono\">She loves jazz.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nieuchwycenie zmiany znaczenia.",
            "wrong": "I think about it now = I think he is right.",
            "right": "✅ <span class=\"font-mono\">I think he is right.</span> / <span class=\"font-mono\">I am thinking about it now.</span>"
        }
    ]
}

